Object.assign(SVGS, EXTRA_SVGS);
SVGS.vampire = SVGS.squid;
function cleanName(html){return String(html).replace(/<span[^>]*class=['"][^'"]*tag-[^'"]*['"][^>]*>[\s\S]*?<\/span>/gi,'').replace(/<[^>]+>/g,'').replace(/\b(BENTHIC|PELAGIC|BENTHOPELAGIC|BENTHIC\s*&\s*PLANKTONIC)\b/gi,'').replace(/\s+/g,' ').trim();}
function uniqueFacts(facts){return [...new Set((facts||[]).filter(Boolean))];}
const creatures = {};
Object.keys(SP_DICT).forEach(id=>{
  const d=SP_DICT[id]; const m=MATCH_DATA.find(x=>x.svgKey===id);
  creatures[id]={id,name:cleanName(d[0]),scientificName:m?.sci||'',description:d[2],diet:d[3],predators:d[4],habitatZone:m?.zoneNames||'',adaptationsShown:[],dvm:DVM_DATA[id]||null,funFacts:uniqueFacts(d[5]),svgKey:id};
});
if(creatures.squid && creatures.vampire){
  creatures.vampire = {
    ...creatures.vampire,
    description: creatures.vampire.description,
    diet: creatures.vampire.diet,
    predators: creatures.vampire.predators,
    svgKey: 'vampire',
    funFacts: uniqueFacts([...(creatures.vampire.funFacts||[]), ...(creatures.squid.funFacts||[])])
  };
  delete creatures.squid;
}
function addCreature(id, data){creatures[id]={id,svgKey:id,adaptationsShown:[],funFacts:[],...creatures[id],...data,funFacts:uniqueFacts([...(creatures[id]?.funFacts||[]),...(data.funFacts||[])])};}
addCreature('copepod',{name:'Copepod',scientificName:'Copepoda',description:'Tiny drifting crustaceans that transfer energy from phytoplankton to larger animals.',diet:'Phytoplankton',predators:'Fish, whales, squid',habitatZone:'Epipelagic to Mesopelagic',dvm:DVM_DATA.copepod,funFacts:['Most only have a single bright red eye!','They are among the most abundant multi-cellular animals on Earth.']});
addCreature('krill',{name:'Krill',scientificName:'Euphausiacea',description:'Small shrimp-like crustaceans that form huge swarms and feed many ocean giants.',diet:'Phytoplankton',predators:'Baleen whales, penguins, squid',habitatZone:'Epipelagic to Mesopelagic',dvm:DVM_DATA.krill,funFacts:['Baleen whales love to eat these swarms.','Their swarms can be so massive they are visible from space.']});
addCreature('humboldt',{name:'Humboldt Squid',scientificName:'Dosidicus gigas',description:'Large, fast squid that flash colors and hunt lanternfish in the water column.',diet:'Lanternfish and other fish',predators:'Sperm whales, sharks',habitatZone:'Epipelagic to Mesopelagic',dvm:DVM_DATA.humboldt,funFacts:['Also known as the Jumbo Squid.','They hunt in large, active shoals.']});
addCreature('siphonophore',{name:'Siphonophore',scientificName:'Siphonophorae',description:'A colony of specialized clones that works together like one drifting animal.',diet:'Small crustaceans and fish',predators:'Sea turtles, fish, nudibranchs',habitatZone:'Open ocean, many depths',dvm:DVM_DATA.siphonophore,funFacts:['A colony of tiny connected clones.','Some deep-sea species can grow longer than a blue whale.']});
addCreature('salp',{name:'Salp',scientificName:'Salpidae',description:'Gelatinous filter feeders that pump water through their bodies and can form long chains.',diet:'Phytoplankton',predators:'Sea turtles and fish',habitatZone:'Open ocean',dvm:DVM_DATA.salp,funFacts:['Their heavy poop safely traps carbon.','They are chordates, closer to vertebrates than jellyfish.']});
addCreature('pteropod',{name:'Sea Butterfly',scientificName:'Pteropoda',description:'Tiny swimming snails with wing-like feet.',diet:'Microscopic plankton',predators:'Sea angels, fish, squid',habitatZone:'Open ocean',dvm:DVM_DATA.pteropod,funFacts:['A tiny swimming snail with wings.','Their delicate shells are sensitive to ocean acidification.']});
addCreature('pyrosome',{name:'Pyrosome',scientificName:'Pyrosomatida',description:'A hollow glowing tube made of many tiny zooids.',diet:'Plankton',predators:'Sea turtles, fish, crabs',habitatZone:'Open ocean',dvm:DVM_DATA.pyrosome,funFacts:['Giant hollow glowing tubes of zooids.','They glow a brilliant blue-green.']});
addCreature('ostracod',{name:'Ostracod',scientificName:'Ostracoda',description:'Tiny shelled crustaceans, some of which make glowing defensive clouds.',diet:'Detritus and plankton',predators:'Fish, shrimp, squid',habitatZone:'Mostly open water and seafloor',dvm:DVM_DATA.ostracod,funFacts:['Vomits bioluminescent fluid to escape.','Also known as seed shrimp.']});
addCreature('medusa',{name:'Atolla Jellyfish',scientificName:'Atolla wyvillei',description:'A deep red jellyfish famous for its blue burglar-alarm light display.',diet:'Zooplankton',predators:'Sea turtles, fish, whales',habitatZone:'Mesopelagic',dvm:DVM_DATA.medusa,funFacts:['Creates a circular flash of blue light.','The flash can attract a larger predator to attack its attacker.']});
addCreature('bluewhale',{name:'Blue Whale',scientificName:'Balaenoptera musculus',description:'The largest animal ever known, using baleen plates to filter huge amounts of krill and plankton.',diet:'Krill and zooplankton',predators:'Orcas may attack calves',habitatZone:'Epipelagic open ocean',adaptationsShown:['Baleen filter feeding'],funFacts:['The Blue Whale is even bigger than the largest dinosaurs.']});
addCreature('dolphin',{name:'Bottlenose Dolphin',scientificName:'Tursiops truncatus',description:'A smart air-breathing marine mammal that hunts near the surface and can dive to follow prey.',diet:'Fish and squid',predators:'Large sharks and orcas',habitatZone:'Epipelagic coastal and open ocean',funFacts:['Dolphins are mammals that stick near the surface but can hold their breath to dive deep.','They use clicks and echoes to sense prey underwater.']});
addCreature('barreleye',{name:'Barreleye Fish',scientificName:'Macropinna microstoma',description:'A twilight-zone fish with a transparent head dome and tubular green eyes that can rotate to look upward for prey silhouettes.',diet:'Small crustaceans and siphonophore tentacles',predators:'Larger deep-sea fish',habitatZone:'Mesopelagic Zone',funFacts:['Its clear forehead lets the eyes look through the top of the head.','The eyes can pivot forward when the fish is feeding.']});
addCreature('blobfish',{name:'Blobfish',scientificName:'Psychrolutes marcidus',description:'A deep-sea fish with soft, gelatinous tissues that stay neutrally buoyant without a gas-filled swim bladder.',diet:'Small crustaceans and drifting invertebrates',predators:'Larger benthic fish',habitatZone:'Bathyal to Abyssal seafloor',funFacts:['It looks droopy at the surface because its body is built for deep pressure, not air.','Its body is less dense than seawater, so it can hover with little effort.']});
addCreature('mussel',{name:'California Mussel',scientificName:'Mytilus californianus',description:'A rocky-shore shellfish that anchors itself in pounding surf using strong byssal threads.',diet:'Plankton filtered from seawater',predators:'Sea stars, otters, shorebirds',habitatZone:'Intertidal Zone',funFacts:['It glues itself to rocks with tough protein threads.','Dense mussel beds create habitat for many smaller tide-pool animals.']});
addCreature('butterflyfish',{name:'Butterflyfish',scientificName:'Chaetodontidae',description:'A thin reef fish built for weaving through coral branches with quick, precise turns.',diet:'Coral polyps, algae, and small invertebrates',predators:'Groupers, snappers, moray eels',habitatZone:'Neritic coral reefs',funFacts:['Its body is compressed side-to-side like a leaf.','Many species have bold eye stripes and false eyespots to confuse predators.']});
addCreature('angelfish',{name:'Marine Angelfish',scientificName:'Pomacanthidae',description:'A laterally compressed reef fish that threads through tight coral spaces with graceful maneuverability.',diet:'Sponges, algae, and small invertebrates',predators:'Larger reef fish',habitatZone:'Neritic coral reefs',funFacts:['Many species change color dramatically as they grow up.','Their deep, flat bodies help them pivot quickly around reef structure.']});
addCreature('octopus',{name:'Octopus',scientificName:'Octopoda',description:'A highly flexible cephalopod that can rapidly change skin color and texture to vanish against rocks, sand, or coral.',diet:'Crabs, shrimp, and fish',predators:'Sharks, moray eels, seals',habitatZone:'Mostly Neritic reefs and seafloor habitats',funFacts:['Its skin contains chromatophores, iridophores, and papillae for color and texture tricks.','An octopus can squeeze through any gap larger than its beak.']});
addCreature('cuttlefish',{name:'Cuttlefish',scientificName:'Sepiida',description:'A hovering cephalopod famous for dynamic camouflage patterns and rapid shifts in skin texture and brightness.',diet:'Shrimp, crabs, and small fish',predators:'Sharks, dolphins, larger fish',habitatZone:'Neritic coastal waters',funFacts:['It can flash moving bands across its body to confuse prey or rivals.','The internal cuttlebone helps control buoyancy.']});
addCreature('penguin',{name:'Penguin',scientificName:'Spheniscidae',description:'A marine diving bird with dark back and bright belly countershading that helps hide it from predators and prey underwater.',diet:'Fish, krill, and squid',predators:'Leopard seals, sharks, orcas',habitatZone:'Cold epipelagic coastal waters',funFacts:['Its flippers are modified wings used to fly through water instead of air.','Countershading helps it blend with dark depths below and bright light above.']});
addCreature('electricray',{name:'Electric Ray',scientificName:'Torpediniformes',description:'A rounded bottom-dwelling ray that can generate strong electrical discharges to stun prey and defend itself.',diet:'Small fish and invertebrates',predators:'Large sharks and marine mammals',habitatZone:'Neritic sandy and muddy seafloors',dvm:DVM_DATA.electricray,funFacts:['Its electric organs are modified muscle tissue.','Some species can produce shocks strong enough to stun a human.']});
addCreature('irukandji',{name:'Irukandji Jellyfish',scientificName:'Carukia barnesi and related cubozoans',description:'A tiny box jellyfish with trailing tentacles and extremely potent venom despite its almost transparent body.',diet:'Small plankton and larval fishes',predators:'Some fish and sea turtles',habitatZone:'Warm coastal epipelagic waters',dvm:DVM_DATA.irukandji,funFacts:['It is small enough to fit on a fingernail, but its sting can be medically serious.','Its transparent bell makes it very hard to spot in the water.']});
addCreature('japanesespidercrab',{name:'Japanese Spider Crab',scientificName:'Macrocheira kaempferi',description:'A giant deep-slope crab with extremely long walking legs and a spiny armored body.',diet:'Carrion, mollusks, and other seafloor animals',predators:'Large fish, octopuses, and humans',habitatZone:'Bathyal continental slope',dvm:DVM_DATA.japanesespidercrab,funFacts:['It has the longest leg span of any living arthropod.','Younger crabs often decorate themselves with sponges and algae for camouflage.']});
addCreature('nautilus',{name:'Nautilus',scientificName:'Nautilus pompilius',description:'A chambered cephalopod that controls buoyancy with gas-filled shell chambers and nightly climbs into shallower slope waters.',diet:'Carrion, crustaceans, and small animals',predators:'Large fish, octopuses, and sharks',habitatZone:'Outer reef slopes and upper bathyal waters',dvm:DVM_DATA.nautilus,funFacts:['It is one of the few living cephalopods with an external shell.','Its shell chambers act like a natural buoyancy system.']});
addCreature('queenangelfish',{name:'Queen Angelfish',scientificName:'Holacanthus ciliaris',description:'A brightly colored Caribbean reef fish with neon blue and gold markings and a dark crown-like spot above the eyes.',diet:'Sponges, tunicates, and algae',predators:'Groupers, sharks, and larger reef fish',habitatZone:'Neritic coral reefs',dvm:DVM_DATA.queenangelfish,funFacts:['Adults often have a crown-like blue ring on the forehead.','They are especially common on Caribbean coral reefs.']});
addCreature('urchin',{name:'Urchin',scientificName:'Echinoidea',description:'A spiny echinoderm that grazes algae from rock and reef surfaces using a five-toothed mouth.',diet:'Algae and biofilm',predators:'Sea otters, triggerfish, and sea stars',habitatZone:'Rocky benthic shallows and reefs',dvm:DVM_DATA.urchin,funFacts:['Its mouth has a five-toothed chewing structure called Aristotle\'s lantern.','Tube feet help it grip rock and move surprisingly well.']});
addCreature('whaleshark',{name:'Whale Shark',scientificName:'Rhincodon typus',description:'The largest fish in the ocean, filtering plankton and small fish through a huge wide mouth.',diet:'Plankton, fish eggs, and small schooling fish',predators:'Large sharks and orcas may threaten juveniles',habitatZone:'Epipelagic open ocean and coastal aggregation sites',dvm:DVM_DATA.whaleshark,funFacts:['Its white spots are unique enough to identify individuals like fingerprints.','Even though it is a shark, it feeds by filtering tiny prey from the water.']});
addCreature('xrayfish',{name:'X-ray Fish',scientificName:'Pristella maxillaris',description:'A small translucent fish whose silvery internal structures show through its nearly see-through body.',diet:'Zooplankton and tiny crustaceans',predators:'Larger reef and coastal fishes',habitatZone:'Shallow coastal and estuarine waters',dvm:DVM_DATA.xrayfish,funFacts:['Its semi-transparent body makes the spine and swim bladder visible.','It gets its name from looking almost see-through.']});
addCreature('yellowfintuna',{name:'Yellowfin Tuna',scientificName:'Thunnus albacares',description:'A fast open-ocean predator with bright yellow finlets and long sickle-shaped dorsal and anal fins.',diet:'Fish, squid, and crustaceans',predators:'Sharks, billfish, and humans',habitatZone:'Epipelagic open ocean',dvm:DVM_DATA.yellowfintuna,funFacts:['Its long yellow fins help make it one of the most recognizable tunas.','It can keep swimming at high speed for long periods.']});
addCreature('zooplankton',{name:'Zooplankton',scientificName:'Various drifting animals',description:'A broad group of drifting ocean animals including copepods, larvae, tiny crustaceans, and gelatinous plankton that feed much of the sea.',diet:'Phytoplankton, microbes, and smaller plankton',predators:'Fish, whales, jellyfish, and seabirds',habitatZone:'All pelagic ocean zones',dvm:DVM_DATA.zooplankton,funFacts:['Their nightly rise toward the surface helps drive the largest daily animal migration on Earth.','Many begin life as microscopic larvae before growing into larger animals.']});
addCreature('moonjelly',{name:'Moon Jelly',scientificName:'Aurelia aurita',description:'A translucent epipelagic jellyfish with a saucer-shaped bell, short fringe tentacles, and four visible horseshoe-shaped reproductive organs.',diet:'Tiny zooplankton, larvae, and other plankton',predators:'Sea turtles, ocean sunfish, larger jellyfish, and seabirds',habitatZone:'Epipelagic coastal and open waters',dvm:{status:'unknown',note:'Many jellyfish show light- or tide-linked vertical movements, but a single reliable day/night depth pair for moon jellies is not appropriate for this app.'},funFacts:['The four pale rings in the bell are the easiest field mark for moon jellies.','They pulse their bell for limited movement but mostly drift with currents.']});
addCreature('flyingfish',{name:'Flying Fish',scientificName:'Exocoetidae',description:'A warm-water surface fish that escapes predators by bursting out of the water and gliding on enlarged wing-like pectoral fins.',diet:'Plankton and small crustaceans',predators:'Tuna, dolphins, mahi-mahi, squid, and seabirds',habitatZone:'Epipelagic open ocean',dvm:{status:'non_migrant',note:'No classic diel vertical migration is usually reported; flying fish are surface-oriented epipelagic fishes.'},funFacts:['Large pectoral fins act like glider wings after the fish accelerates underwater.','The tail can keep beating at the surface to extend a glide.']});
addCreature('sardineherring',{name:'Sardines / Herring',scientificName:'Clupeidae',description:'Small silvery schooling fishes that live near the surface and transfer plankton energy to larger predators.',diet:'Phytoplankton and zooplankton',predators:'Tuna, dolphins, whales, sharks, seabirds, and larger fish',habitatZone:'Epipelagic and neritic surface waters',dvm:{status:'unknown',note:'Many small pelagic fishes shift depth with light and prey, but this broad sardine/herring grouping is not assigned one fixed DVM depth pair.'},funFacts:['Dense schools can confuse predators by looking like one huge flashing shape.','They are forage fish, meaning many larger animals depend on them for food.']});
addCreature('viperfish',{name:'Viperfish',scientificName:'Chauliodus',description:'A fierce mesopelagic predator with long fang-like teeth, photophores, and a lure used to attract prey in dim water.',diet:'Small fish, shrimp, and other crustaceans',predators:'Dolphins, deep-diving fish, sharks, and larger deep-sea predators',habitatZone:'Mesopelagic to upper Bathypelagic Zone',dvm:{status:'migrates',day:'often several hundred meters deep in the mesopelagic',night:'shallower midwater to feed',note:'Viperfishes are commonly treated as mesopelagic vertical migrators, but exact depths vary by species and region.'},funFacts:['Its teeth are so long that the mouth cannot fully close.','Photophores help with camouflage and signaling in dim water.']});
addCreature('strawberrysquid',{name:'Strawberry Squid',scientificName:'Histioteuthis heteropsis',description:'A red mesopelagic squid with one large upward-looking eye and one smaller eye, both useful in the twilight zone.',diet:'Small fish, crustaceans, and other squid',predators:'Sperm whales, dolphins, sharks, and larger fish',habitatZone:'Mesopelagic Zone',dvm:{status:'migrates',day:'200-1,000m in the mesopelagic zone',night:'shallower midwater to hunt',note:'MBARI lists strawberry squid as a twilight-zone midwater animal that migrates shallower at night.'},funFacts:['Its mismatched eyes help scan both the dim water above and bioluminescent flashes below.','The red body appears dark in deep blue water.']});
addCreature('giantsquid',{name:'Giant Squid',scientificName:'Architeuthis dux',description:'A huge deep-ocean squid with dinner-plate-sized eyes and two long feeding tentacles for grabbing prey in dark water.',diet:'Deep-water fish and other squid',predators:'Sperm whales',habitatZone:'Mesopelagic to Bathypelagic slope waters',dvm:{status:'unknown',note:'Giant squid are deep-ocean predators, but regular day/night vertical migration depths are not well established.'},funFacts:['Its eyes are among the largest in the animal kingdom.','Sperm whale stomachs often contain giant squid beaks.']});
addCreature('spermwhale',{name:'Sperm Whale',scientificName:'Physeter macrocephalus',description:'A deep-diving toothed whale that breathes air at the surface but hunts squid in dark mesopelagic and bathypelagic waters.',diet:'Giant squid, other squid, octopus, and deep-water fish',predators:'Orcas may threaten calves',habitatZone:'Epipelagic surface between deep Mesopelagic/Bathypelagic foraging dives',dvm:{status:'non_migrant',note:'Sperm whales make deep foraging dives, but these breath-hold dives are not the same as classic plankton-style diel vertical migration.'},funFacts:['They use powerful echolocation clicks to hunt in total darkness.','They are the largest toothed whales.']});
addCreature('scaleworm',{name:'Scale Worm',scientificName:'Polynoidae',description:'A segmented deep-sea worm with overlapping protective scales, often found around vents, whale falls, and other deep seafloor habitats.',diet:'Small animals, detritus, suspended organic matter, or host tissue depending on species',predators:'Deep-sea fish, crabs, and other benthic predators',habitatZone:'Bathyal to Hadal benthic habitats, including hydrothermal vents',dvm:{status:'non_migrant',note:'Scale worms are benthic animals that crawl on or near the seafloor, not open-water diel vertical migrators.'},funFacts:['Some deep-sea scale worms have elaborate gills beneath their scales for low-oxygen habitats.','Their overlapping scales give them an armored look.']});
addCreature('xenophyophore',{name:'Xenophyophore',scientificName:'Xenophyophorea',description:'A giant single-celled deep-sea organism that builds a delicate sediment test and can live on hadal trench floors.',diet:'Bacteria, tiny particles, and dissolved or fine organic matter',predators:'Small deep-sea invertebrates and deposit feeders',habitatZone:'Abyssal to Hadal seafloor',dvm:{status:'non_migrant',note:'Xenophyophores are benthic single-celled organisms fixed on or within deep seafloor sediments.'},funFacts:['One cell can grow large enough to be seen easily without a microscope.','Their fragile tests can create tiny habitat structure on the deep seafloor.']});
addCreature('manatee',{name:'Manatee',scientificName:'Trichechus manatus',description:'A slow-moving herbivorous marine mammal that grazes in warm shallow coastal waters, estuaries, rivers, and seagrass beds.',diet:'Seagrasses and other aquatic vegetation',predators:'Few natural predators; calves may be threatened by large sharks or crocodiles',habitatZone:'Neritic shallow coastal waters and estuaries',dvm:{status:'non_migrant',note:'Manatees travel seasonally for warm water and forage, but they are not diel vertical migrators.'},funFacts:['They use flexible lips to pull seagrass and other plants into the mouth.','They must surface to breathe air and cannot tolerate prolonged cold water.']});
addCreature('seagrass',{name:'Seagrass',scientificName:'Thalassia testudinum, Halophila johnsonii, and related marine flowering plants',description:'A true flowering plant of shallow coastal waters that anchors sediment, produces oxygen, and forms nursery habitat for many animals.',diet:'Photosynthesis',predators:'Manatees, green sea turtles, urchins, and grazing snails or fishes',habitatZone:'Neritic shallow coastal seagrass meadows',dvm:{status:'non_migrant',note:'Seagrasses are rooted benthic producers, not vertical migrators.'},funFacts:['Turtle grass and Johnsons seagrass are examples highlighted in elementary marine study guides.','Underground rhizomes help stabilize sediment and spread new shoots.']});
addCreature('diatom',{name:'Diatom',scientificName:'Bacillariophyta',description:'A photosynthetic phytoplankton with a glassy silica shell, important in coastal productivity and ocean carbon export.',diet:'Photosynthesis using sunlight, carbon dioxide, and dissolved nutrients',predators:'Copepods, krill, clams, and other filter feeders or grazers',habitatZone:'Epipelagic and neritic sunlit waters',dvm:{status:'non_migrant',note:'Diatoms are drifting primary producers; many are mixed by water movement rather than animal-style DVM.'},funFacts:['Their silica shell is called a frustule.','Diatoms make fatty acids that move up food webs to fish, birds, and mammals.']});
addCreature('quahog',{name:'Quahog Clam',scientificName:'Arctica islandica and Mercenaria mercenaria',description:'A thick-shelled benthic clam that burrows into sandy or muddy coastal seafloor and filter-feeds on microscopic algae.',diet:'Microscopic algae and suspended organic particles filtered from water',predators:'Sea stars, crabs, fish, snails, and seabirds',habitatZone:'Intertidal to Neritic sandy and muddy seafloor',dvm:{status:'non_migrant',note:'Quahogs are burrowing benthic filter feeders, not diel vertical migrators.'},funFacts:['A thick shell and burrowing behavior protect quahogs from many predators.','Ocean quahogs can live for a very long time compared with most clams.']});
addCreature('americanlobster',{name:'American Lobster',scientificName:'Homarus americanus',description:'A large benthic crustacean that shelters in rocky crevices or burrows on coastal and continental-shelf seafloors.',diet:'Clams, mussels, sea urchins, worms, crabs, fish, and carrion',predators:'Cod, wolffish, skates, seals, and humans',habitatZone:'Neritic and shelf benthic habitats',dvm:{status:'non_migrant',note:'American lobsters can migrate seasonally along the shelf, but they are benthic crawlers rather than diel vertical migrators.'},funFacts:['They use claws for crushing and cutting prey.','They molt their hard exoskeleton to grow.']});
addCreature('longfinsquid',{name:'Longfin Squid',scientificName:'Doryteuthis pealeii',description:'A coastal shelf squid that hunts fish and crustaceans, uses chromatophores for rapid color change, and moves vertically between bottom and surface waters.',diet:'Small fish, crustaceans, plankton when young, and sometimes other squid',predators:'Marine mammals, diving birds, sharks, and finfish',habitatZone:'Neritic continental shelf and upper slope',dvm:{status:'migrates',day:'near seabed over shelf mud or sand',night:'upper water column and toward the surface',note:'NOAA Fisheries describes longfin squid as remaining near the seabed by day and moving toward the surface at night.'},funFacts:['Egg capsules are attached in clusters to the ocean bottom.','They are aggressive hunters and can eat prey larger than themselves.']});
addCreature('eyeflashsquid',{name:'Eye-flash Squid',scientificName:'Abralia veranyi',description:'A small mesopelagic squid whose ventral photophores produce counterillumination, hiding its silhouette from predators below.',diet:'Small planktonic crustaceans and other invertebrates',predators:'Larger fishes, squids, dolphins, and deep-diving predators',habitatZone:'Mesopelagic midwater',dvm:{status:'migrates',day:'deep mesopelagic waters',night:'nearer the surface to feed',note:'Eye-flash squid are widely described as daily vertical migrators from deeper daytime water to shallower nighttime feeding depths.'},funFacts:['Photophores on the underside glow to match dim light from above.','This is counterillumination, not passive countershading.']});
addCreature('veinedsquid',{name:'Veined Squid',scientificName:'Loligo forbesii',description:'A coastal and shelf squid used in climate examples because warming and bottom temperature shifts can change its seasonal arrival timing.',diet:'Fish, crustaceans, and other cephalopods',predators:'Marine mammals, large fish, seabirds, and humans',habitatZone:'Neritic coastal shelf and slope waters',dvm:{status:'unknown',note:'Veined squid make seasonal and depth-related movements, but this app does not assign one simple day/night DVM pair.'},funFacts:['Warm years can shift seasonal squid arrival timing dramatically.','Like other squids, it uses jet propulsion and rapid color-changing chromatophores.']});
addCreature('rightwhale',{name:'North Atlantic Right Whale',scientificName:'Eubalaena glacialis',description:'A critically endangered baleen whale that slowly skims dense copepod patches near the surface with long baleen plates.',diet:'Copepods and other tiny zooplankton',predators:'Few natural predators; calves may be attacked by orcas',habitatZone:'Epipelagic coastal and shelf waters',dvm:{status:'non_migrant',note:'Right whales track plankton patches and migrate seasonally, but they are air-breathing surface feeders rather than diel vertical migrators.'},funFacts:['Raised white callosities on the head help scientists identify individuals.','They have no dorsal fin, which helps distinguish them from many other whales.']});
addCreature('humpback',{name:'Humpback Whale',scientificName:'Megaptera novaeangliae',description:'A baleen whale famous for long flippers, songs, and bubble-net feeding on krill or small schooling fish in sunlit waters.',diet:'Krill and small schooling fish',predators:'Orcas may prey on calves',habitatZone:'Epipelagic coastal and open ocean',dvm:{status:'non_migrant',note:'Humpbacks migrate seasonally between feeding and breeding areas, not as classic day-night vertical migrators.'},funFacts:['Groups can blow bubbles in a ring that corrals prey into a tight ball.','The scientific name means big-winged New Englander, a nod to the long flippers.']});
addCreature('orca',{name:'Orca / Killer Whale',scientificName:'Orcinus orca',description:'A large toothed whale and apex predator that hunts cooperatively in pods and uses echolocation to find prey.',diet:'Fish, squid, seals, sea lions, sharks, and sometimes whales depending on ecotype',predators:'No regular natural predators',habitatZone:'Epipelagic coastal and open ocean',dvm:{status:'non_migrant',note:'Orcas dive and travel widely while hunting, but they are not diel vertical migrators.'},funFacts:['Family groups often pass hunting strategies from adults to young.','The black-and-white pattern is strong countershading for a surface predator.']});
addCreature('sealion',{name:'California Sea Lion',scientificName:'Zalophus californianus',description:'An agile pinniped with visible ear flaps and rotating hind flippers, common around coasts and productive shelf waters.',diet:'Fish, squid, and crustaceans',predators:'Orcas and large sharks',habitatZone:'Neritic and epipelagic coastal waters',dvm:{status:'non_migrant',note:'Sea lions make repeated foraging dives, but those breath-hold dives are not plankton-style diel vertical migration.'},funFacts:['Unlike true seals, sea lions can rotate their hind flippers forward to move well on land.','They use whiskers to sense prey movements in cloudy water.']});
addCreature('walrus',{name:'Walrus',scientificName:'Odobenus rosmarus',description:'A large Arctic pinniped with tusks and sensitive whiskers used to find clams and other benthic prey on shallow shelves.',diet:'Clams, snails, worms, and other benthic invertebrates',predators:'Orcas and polar bears',habitatZone:'Polar neritic shelf and surface waters',dvm:{status:'non_migrant',note:'Walruses dive to the seafloor to feed, but they are not diel vertical migrators.'},funFacts:['Tusks help haul the body onto ice and are used in social displays.','Dense whiskers, called vibrissae, help locate buried prey.']});
addCreature('dugong',{name:'Dugong',scientificName:'Dugong dugon',description:'A seagrass-grazing marine mammal of warm shallow coastal waters, closely tied to healthy seagrass meadows.',diet:'Seagrasses and other marine plants',predators:'Large sharks, crocodiles, and orcas may threaten calves or adults',habitatZone:'Neritic shallow seagrass meadows',dvm:{status:'non_migrant',note:'Dugongs move with tides and food but are not diel vertical migrators.'},funFacts:['It is the only strictly marine herbivorous mammal.','A fluked tail separates dugongs from paddle-tailed manatees.']});
addCreature('hammerhead',{name:'Hammerhead Shark',scientificName:'Sphyrnidae',description:'A shark with a wide hammer-shaped head that spreads the senses and helps it scan for prey such as rays.',diet:'Rays, fish, squid, crustaceans, and small sharks',predators:'Larger sharks and orcas',habitatZone:'Epipelagic warm coastal and open waters',dvm:{status:'unknown',note:'Some hammerheads dive or move vertically, but this app does not assign a simple fixed DVM pattern.'},funFacts:['The wide head is called a cephalofoil.','Electroreceptors spread across the head help detect hidden prey in sand.']});
addCreature('cookiecutter',{name:'Cookiecutter Shark',scientificName:'Isistius brasiliensis',description:'A small deep-water shark with a glowing underside and suction-cup mouth that removes round plugs from larger animals.',diet:'Squid, small fish, crustaceans, and circular bites from larger animals',predators:'Large fish and sharks',habitatZone:'Mesopelagic by day and epipelagic at night',dvm:{status:'migrates',day:'deep mesopelagic to bathypelagic water',night:'shallower epipelagic or upper mesopelagic water',note:'Cookiecutter sharks are well known for vertical movements from deep daytime water to shallower nighttime feeding.'},funFacts:['Its glowing belly can hide its silhouette from below.','The dark collar may trick predators into aiming at the shark mouth.']});
addCreature('goblinshark',{name:'Goblin Shark',scientificName:'Mitsukurina owstoni',description:'A rare deep-sea shark with a long flattened snout and jaws that shoot forward to grab prey in dark slope waters.',diet:'Fish, squid, and crustaceans',predators:'Very few known; possibly larger sharks',habitatZone:'Bathypelagic and bathyal slope waters',dvm:{status:'unknown',note:'Goblin sharks are deep-slope predators; regular diel vertical migration is not well established.'},funFacts:['The protrusible jaws can snap forward quickly at prey.','Its long snout contains sensory pores for detecting weak electric fields.']});
addCreature('pufferfish',{name:'Pufferfish',scientificName:'Tetraodontidae',description:'A reef and coastal fish that inflates into a spiky ball when threatened and often carries powerful defensive toxin.',diet:'Algae, mollusks, crustaceans, and small invertebrates',predators:'Sharks and larger fish able to avoid or tolerate defenses',habitatZone:'Neritic reefs, seagrass beds, and coastal waters',dvm:{status:'non_migrant',note:'Pufferfish are shallow coastal fishes, not classic diel vertical migrators.'},funFacts:['Inflating makes the fish much harder to swallow.','Many species have beak-like teeth for crushing shells.']});
addCreature('seahorse',{name:'Seahorse',scientificName:'Hippocampus',description:'A small coastal fish that anchors to seagrass or coral with a curled tail and ambushes tiny prey with a tube snout.',diet:'Tiny crustaceans and planktonic animals',predators:'Crabs, rays, tuna, and other fish',habitatZone:'Neritic seagrass beds, mangroves, and coral reefs',dvm:{status:'non_migrant',note:'Seahorses cling to shallow habitats and do not make classic DVM migrations.'},funFacts:['Male seahorses carry developing young in a brood pouch.','Their prehensile tail acts like a tiny anchor in moving water.']});
addCreature('mantisshrimp',{name:'Mantis Shrimp',scientificName:'Stomatopoda',description:'A colorful reef crustacean with raptorial claws and unusually complex eyes for hunting in shallow habitats.',diet:'Snails, crabs, fish, worms, and other invertebrates',predators:'Large fish, octopuses, sharks, and humans',habitatZone:'Neritic reefs and sandy burrows',dvm:{status:'non_migrant',note:'Mantis shrimp are burrow or reef animals rather than diel vertical migrators.'},funFacts:['Some species punch prey with club-like claws at extreme speed.','Each eye can judge depth on its own, which helps with precise strikes.']});
addCreature('lionfish',{name:'Lionfish',scientificName:'Pterois volitans and relatives',description:'A striped reef predator with fanlike fins and venomous spines, famous as an invasive species in the western Atlantic.',diet:'Small fish, shrimp, and crabs',predators:'Groupers, sharks, moray eels, and humans',habitatZone:'Neritic coral reefs and rocky habitats',dvm:{status:'non_migrant',note:'Lionfish may move around reefs but are not diel vertical migrators.'},funFacts:['Venomous dorsal spines discourage many predators.','In invaded reefs, lionfish can strongly reduce small native fish populations.']});
addCreature('horseshoecrab',{name:'Horseshoe Crab',scientificName:'Limulus polyphemus',description:'An ancient coastal arthropod that crawls on sandy or muddy bottoms and comes ashore to spawn on beaches.',diet:'Worms, clams, small crustaceans, and detritus',predators:'Sea turtles, sharks, fish, and migratory shorebirds that eat the eggs',habitatZone:'Intertidal beaches and neritic sandy seafloor',dvm:{status:'non_migrant',note:'Horseshoe crabs migrate onto beaches to spawn, but they are benthic crawlers rather than vertical migrators.'},funFacts:['Their copper-based hemocyanin makes the blood blue.','Mass spawning events feed migrating shorebirds with energy-rich eggs.']});
addCreature('oyster',{name:'Oyster',scientificName:'Ostreidae',description:'A reef-building bivalve that cements to hard surfaces and filters plankton and particles from coastal water.',diet:'Phytoplankton and suspended organic particles',predators:'Sea stars, oyster drills, crabs, fish, and humans',habitatZone:'Intertidal to neritic oyster reefs and estuaries',dvm:{status:'non_migrant',note:'Oysters are attached benthic filter feeders, not diel vertical migrators.'},funFacts:['Oyster reefs create habitat for fish, crabs, and many small invertebrates.','A single oyster can filter many liters of water per day under good conditions.']});
addCreature('fangtooth',{name:'Fangtooth Fish',scientificName:'Anoplogaster cornuta',description:'A dark deep-sea fish with oversized teeth, a large head, and pressure-tolerant adaptations for dim midwater.',diet:'Fish, squid, and crustaceans',predators:'Tuna, marlin, sharks, and larger deep-sea predators',habitatZone:'Mesopelagic to Bathypelagic Zone',dvm:{status:'migrates',day:'deeper mesopelagic or bathypelagic water',night:'shallower twilight water to feed',note:'Fangtooth fish are commonly listed among deep midwater fishes that may move upward at night.'},funFacts:['Special sockets in the skull make room for the huge lower fangs.','Despite the scary teeth, adults are only about the length of a pencil.']});
addCreature('stoplightloosejaw',{name:'Stoplight Loosejaw',scientificName:'Malacosteus niger',description:'A mesopelagic dragonfish relative that can produce and see red bioluminescent light, giving it a stealthy hunting trick.',diet:'Small fish and crustaceans',predators:'Larger deep-sea fish, squid, and marine mammals',habitatZone:'Mesopelagic Zone',dvm:{status:'migrates',day:'deep twilight water',night:'shallower mesopelagic water',note:'Loosejaws are mesopelagic predators often associated with vertical movements following prey layers.'},funFacts:['Most deep-sea animals cannot see red light well, so red light can act like a private flashlight.','The lower jaw is extremely loose and can swing open wide.']});
addCreature('glasssquid',{name:'Glass Squid',scientificName:'Cranchiidae',description:'A mostly transparent squid family whose see-through body and photophores help hide it in the twilight ocean.',diet:'Small fish, crustaceans, and other planktonic animals',predators:'Sperm whales, dolphins, fish, sharks, and larger squid',habitatZone:'Mesopelagic open ocean',dvm:{status:'migrates',day:'mesopelagic twilight water',night:'shallower upper water to feed',note:'Many glass squids are midwater animals that participate in diel vertical movements.'},funFacts:['Some species hold their arms over the head, making a cranchiid squid look like a little glass balloon.','Photophores below the eyes can help erase shadows.']});
addCreature('bigfinsquid',{name:'Bigfin Squid',scientificName:'Magnapinna',description:'A mysterious deep-sea squid with giant fins and extraordinarily long arm filaments seen in very deep open water.',diet:'Unknown; likely small animals captured with long arm filaments',predators:'Large deep-diving predators such as sperm whales may prey on deep squids',habitatZone:'Bathypelagic to Abyssopelagic deep water',dvm:{status:'unknown',note:'Bigfin squid are deep-water animals, but a regular day-night migration pattern is not established.'},funFacts:['The long dangling arm filaments can be many times longer than the body.','ROV videos are among the main ways scientists study this rare animal.']});
addCreature('yeticrab',{name:'Yeti Crab',scientificName:'Kiwa hirsuta and relatives',description:'A pale deep-sea crab with hairy claws that lives near hydrothermal vents and cold seeps where chemosynthetic bacteria are food.',diet:'Bacteria grown on hairy claws, mussels, shrimp, and detritus depending on species',predators:'Deep-sea fish, octopuses, and larger crabs',habitatZone:'Bathyal hydrothermal vents and seep habitats',dvm:{status:'non_migrant',note:'Yeti crabs are vent-associated benthic animals, not diel vertical migrators.'},funFacts:['Hairy claws can host bacteria that the crab harvests for food.','The pale color fits a habitat without sunlight.']});
addCreature('ventshrimp',{name:'Vent Shrimp',scientificName:'Rimicaris exoculata and related vent shrimp',description:'A pale shrimp of hydrothermal vents that depends on chemosynthetic bacteria and uses a light-sensing organ instead of normal eyes.',diet:'Chemosynthetic bacteria and organic particles at vents',predators:'Vent crabs, fish, and other deep-sea predators',habitatZone:'Bathyal hydrothermal vent communities',dvm:{status:'non_migrant',note:'Vent shrimp cluster around seafloor vents and do not make diel vertical migrations.'},funFacts:['Some vent shrimp have a dorsal light-sensing organ that may detect faint vent glow.','They live where chemical energy, not sunlight, powers the food web.']});
